const input = $input.first().json;
const { id, categoria, segmento, titulo, contenido, _action } = input.body || input;

if (!_action) {
  throw new Error('_action es requerido (create, update, delete)');
}

if (_action === 'delete' && !id) {
  throw new Error('id es requerido para delete');
}

if (_action !== 'delete' && (!categoria || !segmento || !titulo || !contenido)) {
  throw new Error('categoria, segmento, titulo y contenido son requeridos');
}

let query = '';

if (_action === 'create') {
  query = `INSERT INTO conocimiento_academia (categoria, segmento, titulo, contenido, activo) VALUES ('${categoria}', '${segmento}', '${titulo.replace(/'/g, "''")}', '${contenido.replace(/'/g, "''")}', true) RETURNING id, categoria, segmento, titulo, contenido, activo;`;
}
else if (_action === 'update') {
  if (!id) throw new Error('id es requerido para update');
  query = `UPDATE conocimiento_academia SET categoria = '${categoria}', segmento = '${segmento}', titulo = '${titulo.replace(/'/g, "''")}', contenido = '${contenido.replace(/'/g, "''")}' WHERE id = ${parseInt(id)} RETURNING id, categoria, segmento, titulo, contenido, activo;`;
}
else if (_action === 'delete') {
  if (!id) throw new Error('id es requerido para delete');
  query = `DELETE FROM conocimiento_academia WHERE id = ${parseInt(id)} RETURNING id;`;
}

return [{
  json: {
    query,
    _action
  }
}];

const resultado = $('query_db').all();
const action = $('build_query').first().json._action;

if (action === 'delete') {
  return [{
    json: {
      success: true,
      message: 'Item eliminado correctamente',
      item: null
    }
  }];
}

const item = resultado[0]?.json || null;

return [{
  json: {
    success: true,
    message: `Item ${action === 'create' ? 'creado' : 'actualizado'} correctamente`,
    item
  }
}];
